import { OllamaClient } from '../ollama.js';
import { loadConfig } from '../config.js';

export async function bridgeCommand(program) {
  const bridgeCmd = new Command('bridge');

  bridgeCmd
    .argument('<endpoint>', 'Endpoint to bridge to')
    .description('Bridge operations between systems')
    .option('-d, --data <data>', 'Data to send through the bridge', '{}')
    .option('-m, --method <method>', 'HTTP method to use', 'GET')
    .option('-m, --model <model>', 'Ollama model to use', 'llama3.1')
    .action(async (endpoint, options) => {
      try {
        // Load config
        const config = await loadConfig();
        const model = options.model || config.ollama?.model || 'llama3.1';

        // Initialize Ollama client
        const ollama = new OllamaClient(model);

        let prompt = `Create a bridge operation to the endpoint: ${endpoint}\n\n`;
        prompt += "Operation details:\n";
        prompt += `- Method: ${options.method}\n`;
        prompt += `- Data: ${options.data}\n\n`;
        prompt += "Generate the appropriate code to perform this bridge operation, considering:\n";
        prompt += "- Authentication if needed\n";
        prompt += "- Error handling\n";
        prompt += "- Response processing\n";
        prompt += "- Security considerations\n";
        prompt += "- Best practices for API communication\n\n";
        prompt += "Provide the implementation code for the bridge operation.";

        console.log(`Creating bridge to ${endpoint}...\n`);
        const bridgeCode = await ollama.generate(prompt, { temperature: 0.5 });
        console.log(bridgeCode);
      } catch (error) {
        console.error(`Error: ${error.message}`);
        process.exit(1);
      }
    });

  program.addCommand(bridgeCmd);
}

