import { generateBlogPost, optimizeContent, scheduleContent, publishContent, auditSEO } from '../blog_seo.js';

export async function blogCommand(program) {
  const blogCmd = new Command('blog');

  // blog:post command
  const postCmd = new Command('post');
  postCmd
    .argument('<topic>', 'Topic for the blog post')
    .option('-a, --audience <audience>', 'Target audience')
    .option('-t, --tone <tone>', 'Writing tone')
    .option('-l, --length <words>', 'Expected length in words')
    .description('Generate blog content')
    .action(async (topic, options) => {
      try {
        const genOptions = {
          audience: options.audience,
          tone: options.tone,
          length: options.length
        };

        const result = await generateBlogPost(topic, genOptions);

        if (result.success) {
          console.log(`✅ Blog post generated: ${result.path}`);
        } else {
          console.error(`Blog post generation failed: ${result.error}`);
        }
      } catch (error) {
        console.error(`Error generating blog post: ${error.message}`);
      }
    });

  // blog:optimize command
  const optimizeCmd = new Command('optimize');
  optimizeCmd
    .argument('<file-path>', 'Path to the content file to optimize')
    .description('SEO analysis and optimization')
    .action(async (filePath) => {
      try {
        const result = await optimizeContent(filePath);

        if (result.success) {
          console.log(`✅ Content optimized: ${result.path}`);
        } else {
          console.error(`Content optimization failed: ${result.error}`);
        }
      } catch (error) {
        console.error(`Error optimizing content: ${error.message}`);
      }
    });

  // blog:schedule command
  const scheduleCmd = new Command('schedule');
  scheduleCmd
    .argument('<date>', 'Scheduled date (YYYY-MM-DD)')
    .argument('<content-path>', 'Path to the content')
    .option('-p, --platform <platform>', 'Platform to publish to', 'all')
    .description('Publishing calendar management')
    .action(async (date, contentPath, options) => {
      try {
        const result = await scheduleContent(date, contentPath, options.platform);

        if (result.success) {
          console.log(`✅ Content scheduled for ${result.date} on ${result.platform}`);
        } else {
          console.error(`Scheduling failed: ${result.error}`);
        }
      } catch (error) {
        console.error(`Error scheduling content: ${error.message}`);
      }
    });

  // blog:publish command
  const publishCmd = new Command('publish');
  publishCmd
    .argument('<content-path>', 'Path to the content to publish')
    .option('-p, --platforms <platforms>', 'Comma-separated list of platforms', 'website')
    .description('Multi-platform publishing')
    .action(async (contentPath, options) => {
      try {
        const platforms = options.platforms.split(',').map(p => p.trim());
        const result = await publishContent(contentPath, platforms);

        if (result.success) {
          console.log(`✅ Content published to: ${result.platforms.join(', ')}`);
        } else {
          console.error(`Publishing failed: ${result.error}`);
        }
      } catch (error) {
        console.error(`Error publishing content: ${error.message}`);
      }
    });

  blogCmd.addCommand(postCmd);
  blogCmd.addCommand(optimizeCmd);
  blogCmd.addCommand(scheduleCmd);
  blogCmd.addCommand(publishCmd);

  program.addCommand(blogCmd);
}

export async function seoCommand(program) {
  const seoCmd = new Command('seo');

  // seo:audit command
  const auditCmd = new Command('audit');
  auditCmd
    .argument('<url>', 'URL to audit')
    .option('-f, --format <format>', 'Output format', 'detailed')
    .description('Site SEO analysis')
    .action(async (url, options) => {
      try {
        const result = await auditSEO(url);

        if (result.success) {
          console.log(`✅ SEO audit completed: ${result.report}`);
        } else {
          console.error(`SEO audit failed: ${result.error}`);
        }
      } catch (error) {
        console.error(`Error performing SEO audit: ${error.message}`);
      }
    });

  seoCmd.addCommand(auditCmd);
  program.addCommand(seoCmd);
}

