import { runSequential, runParallel, runConditional, runWithRetry } from '../batch_operations.js';

export async function batchCommand(program) {
  const batchCmd = new Command('batch');

  // batch:run command
  const runCmd = new Command('run');
  runCmd
    .argument('<commands...>', 'Commands to run sequentially')
    .option('-c, --continue-on-error', 'Continue on error')
    .description('Run multiple commands sequentially')
    .action(async (commands, options) => {
      try {
        const result = await runSequential(commands, { continueOnError: options.continueOnError });

        if (result.success) {
          console.log(`✅ Batch completed successfully in ${result.duration}ms`);
          console.log(`📊 ${result.results.length} commands executed`);
        } else {
          console.log(`⚠️  Batch completed with some errors in ${result.duration}ms`);
          console.log(`📊 ${result.results.filter(r => r.success).length} succeeded, ${result.results.filter(r => !r.success).length} failed`);
        }
      } catch (error) {
        console.error(`Error running batch: ${error.message}`);
      }
    });

  // batch:parallel command
  const parallelCmd = new Command('parallel');
  parallelCmd
    .argument('<commands...>', 'Commands to run in parallel')
    .description('Run commands in parallel')
    .action(async (commands) => {
      try {
        const result = await runParallel(commands);

        if (result.success) {
          console.log(`✅ Parallel batch completed successfully in ${result.duration}ms`);
          console.log(`📊 ${result.results.length} commands executed in parallel`);
        } else {
          console.log(`⚠️  Parallel batch completed with some errors in ${result.duration}ms`);
          console.log(`📊 ${result.results.filter(r => r.success).length} succeeded, ${result.results.filter(r => !r.success).length} failed`);
        }
      } catch (error) {
        console.error(`Error running parallel batch: ${error.message}`);
      }
    });

  // batch:conditional command
  const conditionalCmd = new Command('conditional');
  conditionalCmd
    .argument('<commands-json>', 'JSON string of conditional commands')
    .option('-c, --continue-on-error', 'Continue on error')
    .description('Conditional execution logic')
    .action(async (commandsJson, options) => {
      try {
        const commands = JSON.parse(commandsJson);
        const result = await runConditional(commands, { continueOnError: options.continueOnError });

        if (result.success) {
          console.log(`✅ Conditional batch completed successfully in ${result.duration}ms`);
          console.log(`📊 ${result.results.length} commands processed`);
        } else {
          console.log(`⚠️  Conditional batch completed with some issues in ${result.duration}ms`);
        }
      } catch (error) {
        console.error(`Error running conditional batch: ${error.message}`);
      }
    });

  // batch:retry command
  const retryCmd = new Command('retry');
  retryCmd
    .argument('<command>', 'Command to retry')
    .option('-m, --max-retries <count>', 'Maximum retries', '3')
    .option('-d, --delay <ms>', 'Initial delay between retries (ms)', '1000')
    .description('Retry logic for failed operations')
    .action(async (command, options) => {
      try {
        const retryOptions = {
          maxRetries: parseInt(options.maxRetries),
          delay: parseInt(options.delay)
        };

        const result = await runWithRetry(command, retryOptions);

        if (result.success) {
          console.log(`✅ Command succeeded after ${result.attempts} attempts`);
        } else {
          console.log(`❌ Command failed after ${result.attempts} attempts`);
        }
      } catch (error) {
        console.error(`Error running command with retry: ${error.message}`);
      }
    });

  batchCmd.addCommand(runCmd);
  batchCmd.addCommand(parallelCmd);
  batchCmd.addCommand(conditionalCmd);
  batchCmd.addCommand(retryCmd);

  program.addCommand(batchCmd);
}

