import { logChange, queryLogs, performComplianceCheck, generateComplianceReport } from '../audit.js';

export async function auditCommand(program) {
  const auditCmd = new Command('audit');

  // audit:changes command
  const changesCmd = new Command('changes');
  changesCmd
    .description('Track what Alfred changed')
    .option('-o, --operation <operation>', 'Filter by operation type')
    .option('-u, --user <user>', 'Filter by user')
    .option('-s, --start-date <date>', 'Start date (YYYY-MM-DD)')
    .option('-e, --end-date <date>', 'End date (YYYY-MM-DD)')
    .option('-l, --limit <count>', 'Limit results', '50')
    .action(async (options) => {
      try {
        const filters = {
          operation: options.operation,
          user: options.user,
          startDate: options.startDate,
          endDate: options.endDate,
          limit: parseInt(options.limit)
        };

        const logs = await queryLogs(filters);

        console.log(`📋 Found ${logs.length} audit records:`);
        logs.forEach((log, index) => {
          console.log(`${index + 1}. ${log.operation} - ${log.timestamp}`);
          console.log(`   User: ${log.user_id}`);
          console.log(`   Details: ${JSON.stringify(log.details, null, 2)}`);
        });
      } catch (error) {
        console.error(`Error querying audit logs: ${error.message}`);
      }
    });

  // audit:log command
  const logCmd = new Command('log');
  logCmd
    .description('Query operation logs')
    .option('-o, --operation <operation>', 'Filter by operation type')
    .option('-u, --user <user>', 'Filter by user')
    .option('-s, --start-date <date>', 'Start date (YYYY-MM-DD)')
    .option('-e, --end-date <date>', 'End date (YYYY-MM-DD)')
    .option('-l, --limit <count>', 'Limit results', '50')
    .action(async (options) => {
      try {
        const filters = {
          operation: options.operation,
          user: options.user,
          startDate: options.startDate,
          endDate: options.endDate,
          limit: parseInt(options.limit)
        };

        const logs = await queryLogs(filters);

        console.log(`📋 Operation logs (${logs.length} records):`);
        logs.forEach((log, index) => {
          console.log(`${index + 1}. ${log.operation} - ${log.timestamp}`);
        });
      } catch (error) {
        console.error(`Error querying logs: ${error.message}`);
      }
    });

  // compliance:check command
  const complianceCheckCmd = new Command('compliance:check');
  complianceCheckCmd
    .argument('<type>', 'Compliance check type: security, data_protection, access_control, audit_trail')
    .description('Security/compliance checks')
    .action(async (type) => {
      try {
        const result = await performComplianceCheck(type);

        if (result.success) {
          console.log(`✅ Compliance check completed: ${type}`);
          console.log(JSON.stringify(result.results, null, 2));
        } else {
          console.error(`❌ Compliance check failed: ${result.error}`);
        }
      } catch (error) {
        console.error(`Error performing compliance check: ${error.message}`);
      }
    });

  // compliance:report command
  const complianceReportCmd = new Command('compliance:report');
  complianceReportCmd
    .argument('<type>', 'Report type: security, access, operations')
    .option('-p, --period <period>', 'Period: daily, weekly, monthly, yearly', 'monthly')
    .description('Generate compliance reports')
    .action(async (type, options) => {
      try {
        const result = await generateComplianceReport(type, options.period);

        if (result.success) {
          console.log(`✅ Compliance report generated: ${result.path}`);
        } else {
          console.error(`❌ Report generation failed: ${result.error}`);
        }
      } catch (error) {
        console.error(`Error generating compliance report: ${error.message}`);
      }
    });

  auditCmd.addCommand(changesCmd);
  auditCmd.addCommand(logCmd);
  auditCmd.addCommand(complianceCheckCmd);
  auditCmd.addCommand(complianceReportCmd);

  program.addCommand(auditCmd);
}

