import { getFileContext, getDirectoryContext, chunkContent } from '../context.js';
import { OllamaClient, getClientForCategory } from '../ollama.js';
import { loadConfig } from '../config.js';

export async function analyzeCommand(program) {
  const analyzeCmd = new Command('analyze');

  analyzeCmd
    .argument('<target>', 'file or directory to analyze')
    .description('Analyze code for potential issues, improvements, and insights')
    .option('-m, --model <model>', 'Ollama model to use', 'llama3.1')
    .action(async (target, options) => {
      try {
        // Load config
        const config = await loadConfig();
        const model = options.model || config.ollama?.model || 'llama3.1';

        // Initialize Ollama client with coding category for analysis
        const ollama = new OllamaClient(options.model ? model : null, null, 'coding');

        // Determine if target is file or directory
        const stats = await import('fs').then(fs => fs.promises.stat(target));
        let context;

        if (stats.isDirectory()) {
          context = await getDirectoryContext(target);
        } else {
          context = [await getFileContext(target)];
        }

        // Prepare prompt for analysis
        let prompt = "Please analyze the following code for potential issues, improvements, and insights:\n\n";

        for (const ctx of context) {
          const chunks = chunkContent(ctx.content);
          for (const chunk of chunks) {
            prompt += `\n--- FILE: ${ctx.path} ---\n${chunk}\n`;
          }
        }

        prompt += "\nFocus on code quality, potential bugs, performance issues, security concerns, and best practices.";

        // Generate analysis
        console.log('Analyzing code...\n');
        const analysis = await ollama.generate(prompt, { temperature: 0.1 });
        console.log(analysis);
      } catch (error) {
        console.error(`Error: ${error.message}`);
        process.exit(1);
      }
    });

  program.addCommand(analyzeCmd);
}

